import React, { useEffect, useRef, useState } from 'react';
import '../styles/GameCanvas.css';
import { AWS_ICON_CATEGORIES, SERVICE_MAPPINGS } from '../services/IconResolver';

const S3_BUCKET_URL = 'https://hackthon-backend-files-ep-2024.s3.amazonaws.com';
const ICONS_BASE_PATH = '/amazon-icons-set/Architecture-Service-Icons_06072024';
const S3_ROCKET_PATH = `${S3_BUCKET_URL}/games/rocket`;
const FIREBALL_PATH = `${S3_BUCKET_URL}/games/bullet/fireball.png`;

const GameCanvas = () => {
  // --------------------------------------------------
  //                   STATE
  // --------------------------------------------------
  const [timeLeft, setTimeLeft] = useState(60);
  const [score, setScore] = useState(0);
  const [selectedRocket, setSelectedRocket] = useState(() => {
    const savedRocket = localStorage.getItem('selectedRocket');
    return savedRocket || null;
  });
  const [showNameModal, setShowNameModal] = useState(true);
  const [tempPlayerName, setTempPlayerName] = useState('');
  const [nameError, setNameError] = useState('');
  const [playerName, setPlayerName] = useState(() => {
    const savedName = localStorage.getItem('playerName');
    return savedName || '';
  });

  // Single mission approach
  const [missionCategory, setMissionCategory] = useState('');
  const [missionText, setMissionText] = useState('');
  const [missionDisplayName, setMissionDisplayName] = useState('');

  const [gameStarted, setGameStarted] = useState(false);
  const [gameOver, setGameOver] = useState(false);
  const [gameOverHandled, setGameOverHandled] = useState(false);

  const [highScores, setHighScores] = useState(() => {
    const saved = localStorage.getItem('highScores');
    return saved ? JSON.parse(saved) : [];
  });

  // --------------------------------------------------
  //                   REFS
  // --------------------------------------------------
  const canvasRef = useRef(null);
  const iconsRef = useRef([]);
  const bulletsRef = useRef([]);
  const feedbacksRef = useRef([]);
  const rocketImage = useRef(new Image());
  const fireballImage = useRef(new Image());

  fireballImage.src = FIREBALL_PATH;

  // Gun
  const gunRef = useRef({
    x: 400 - 25,
    y: 800 - 100,
    width: 120,
    height: 120,
  });

  // Particles
  const particlesRef = useRef([]);

  // Sounds
  const sounds = useRef({});
  const [soundsLoaded, setSoundsLoaded] = useState(false);
  const [isMuted, setIsMuted] = useState(false);

  // --------------------------------------------------
  //       LOADING & MOUNT / UNMOUNT
  // --------------------------------------------------
  // Load rocket
  useEffect(() => {
    rocketImage.current.src = selectedRocket;
  }, [selectedRocket]);

  // Clear localStorage (optional) to always start fresh
  useEffect(() => {
    localStorage.removeItem('playerName');
    localStorage.removeItem('selectedRocket');
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      setGameStarted(false);
      setShowRocketModal(true);
    };
  }, []);

  // Initialize game
  useEffect(() => {
    if (canvasRef.current) {
      const canvas = canvasRef.current;
      canvas.width = 1200;
      canvas.height = 800;

      const ctx = canvas.getContext('2d');
      ctx.imageSmoothingEnabled = true;

      // Start game loop once we have a rocket & gameStarted
      if (gameStarted && selectedRocket) {
        console.log('Game started => picking new category & starting loop');
        NewCategoryMission();
        requestAnimationFrame(gameLoop);
      }
    }
  }, [gameStarted, selectedRocket]);

  // Mouse events
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      let newX = e.clientX - rect.left - gunRef.current.width / 2;
      // Bound the gun position so it doesn't go off-canvas
      newX = Math.max(-30, Math.min(newX, canvas.width - gunRef.current.width + 30));
      gunRef.current.x = newX;
    };

    const handleCanvasClick = () => {
      if (!gameStarted || timeLeft <= 0) return;
      playSound('shoot');
      bulletsRef.current.push({
        x: gunRef.current.x + gunRef.current.width / 2 - 10,
        y: gunRef.current.y - 20,
      });
    };

    canvas.addEventListener('mousemove', handleMouseMove);
    canvas.addEventListener('click', handleCanvasClick);

    return () => {
      canvas.removeEventListener('mousemove', handleMouseMove);
      canvas.removeEventListener('click', handleCanvasClick);
    };
  }, [gameStarted, timeLeft]);

  // --------------------------------------------------
  //                RANDOM CATEGORY
  // --------------------------------------------------
  const pickRandomCategoryKey = () => {
    const allKeys = Object.keys(AWS_ICON_CATEGORIES);
    const randIndex = Math.floor(Math.random() * allKeys.length);
    return allKeys[randIndex];
  };

  // Called every time we need a new category
  const NewCategoryMission = () => {
    if (!gameStarted) {
      console.log('Game not started, skipping NewCategoryMission');
      return;
    }
    iconsRef.current = [];

    // 1) Pick random key
    const catKey = pickRandomCategoryKey();
    const catPath = AWS_ICON_CATEGORIES[catKey]; // e.g. "Arch_Quantum-Technologies"

    // 2) Build friendly name & text
    const displayName = catKey
      .split('_')
      .map(s => s.charAt(0).toUpperCase() + s.slice(1).toLowerCase())
      .join(' ');

    const newMissionText = `Shoot the ${displayName} icons!`;

    // 3) Update states
    setMissionCategory(catPath);
    setMissionDisplayName(displayName);
    setMissionText(newMissionText);

    // Log to ensure it matches UI
    console.log('--- NewCategoryMission ---');
    console.log('Category Path:', catPath);
    console.log('Mission DisplayName:', displayName);
    console.log('Mission Text:', newMissionText);

    // 4) Spawn icons
    spawnIconsForCategory(catPath);
  };

  // --------------------------------------------------
  //        ICONS FOR CHOSEN CATEGORY + DISTRACTORS
  // --------------------------------------------------
  const spawnIconsForCategory = (catPath) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const getRandomX = () => Math.floor(Math.random() * (canvas.width - 50));
    const positions = [];

    // All icons that match catPath => correct category
    const categoryIcons = Object.entries(SERVICE_MAPPINGS)
      .filter(([_, path]) => path.includes(catPath))
      .map(([name, path]) => ({
        path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
        name,
        // "type" must match catPath for +5
        type: path.split('/')[0],
      }));

    // Others => distractors
    const otherIcons = Object.entries(SERVICE_MAPPINGS)
      .filter(([_, path]) => !path.includes(catPath))
      .map(([name, path]) => ({
        path: `${S3_BUCKET_URL}${ICONS_BASE_PATH}/${path}`,
        name,
        type: path.split('/')[0],
      }));

    // A) Pick 4 from correct category
    let selectedCategoryIcons = [];
    if (categoryIcons.length <= 4 && categoryIcons.length > 0) {
      while (selectedCategoryIcons.length < 4) {
        selectedCategoryIcons.push(
          ...categoryIcons.slice(0, 4 - selectedCategoryIcons.length)
        );
      }
    } else if (categoryIcons.length > 4) {
      const shuffled = [...categoryIcons].sort(() => 0.5 - Math.random());
      selectedCategoryIcons = shuffled.slice(0, 4);
    }

    // B) Pick 6 from other categories
    const distractors = [];
    const usedCats = new Set();

    // Group them by type
    const catIconMap = otherIcons.reduce((acc, icon) => {
      if (!acc[icon.type]) acc[icon.type] = [];
      acc[icon.type].push(icon);
      return acc;
    }, {});

    const availableTypes = Object.keys(catIconMap).filter(t => t !== catPath);
    const shuffledTypes = availableTypes.sort(() => 0.5 - Math.random());

    for (let i = 0; i < shuffledTypes.length && distractors.length < 6; i++) {
      const typeKey = shuffledTypes[i];
      if (usedCats.has(typeKey)) continue;
      const iconsInType = catIconMap[typeKey];
      if (iconsInType?.length) {
        const r = Math.floor(Math.random() * iconsInType.length);
        distractors.push(iconsInType[r]);
        usedCats.add(typeKey);
      }
    }

    if (distractors.length < 6) {
      const leftover = otherIcons.filter(icon => !distractors.includes(icon));
      const shuf = leftover.sort(() => 0.5 - Math.random());
      distractors.push(...shuf.slice(0, 6 - distractors.length));
    }

    console.log(`Correct icons: ${selectedCategoryIcons.map(i => i.name).join(', ')}`);
    console.log(`Distractor icons: ${distractors.map(i => i.name).join(', ')}`);

    // Add correct icons
    selectedCategoryIcons.forEach(iconInfo => {
      let x = getRandomX();
      while (positions.some(px => Math.abs(px - x) < 50)) {
        x = getRandomX();
      }
      positions.push(x);

      const iconImg = new Image();
      iconImg.src = iconInfo.path;

      iconsRef.current.push({
        x,
        y: -50,
        name: iconInfo.name,
        image: iconImg,
        type: iconInfo.type, // e.g. "Arch_Quantum-Technologies"
        hit: false,
      });
    });

    // Add distractors
    distractors.forEach(iconInfo => {
      let x = getRandomX();
      while (positions.some(px => Math.abs(px - x) < 50)) {
        x = getRandomX();
      }
      positions.push(x);

      const iconImg = new Image();
      iconImg.src = iconInfo.path;

      iconsRef.current.push({
        x,
        y: -50,
        name: iconInfo.name,
        image: iconImg,
        type: iconInfo.type,
        hit: false,
      });
    });
  };

  // --------------------------------------------------
  //          COLLISION & SCORING
  // --------------------------------------------------
  const checkCollisions = () => {
    const canvas = canvasRef.current;
    const bullets = bulletsRef.current;
    const icons = iconsRef.current;

    icons.forEach((icon, iconIndex) => {
      bulletsRef.current = bulletsRef.current.filter((bullet) => {
        // The original bounding-box check
        if (
          bullet.x > icon.x &&
          bullet.x < icon.x + 50 &&
          bullet.y > icon.y &&
          bullet.y < icon.y + 50
        ) {
          // It's a hit
          icon.hit = true;

          if (icon.type === missionCategory) {
            // correct
            const heightPct = 1 - icon.y / canvas.height;
            const heightBonus = Math.floor(heightPct * 20);
            const points = 5 + heightBonus;

            setScore(prevScore => {
              const newScore = prevScore + points;
              // If new high, or super shot
              if (newScore > Math.max(...highScores.map(s => s.score) || [0])) {
                showCheerleaderMessage('highScore');
              } else if (heightBonus > 15) {
                showCheerleaderMessage('goodShot');
              }
              return newScore;
            });

            showFeedback(icon.x, icon.y, true, points, icon.name);
            playSound('correct');
            createExplosion(icon.x + 25, icon.y + 25, '#4CAF50');
          } else {
            // wrong
            setScore(prev => prev - 5);
            showFeedback(icon.x, icon.y, false, -5, icon.name);
            playSound('incorrect');
          }

          icons.splice(iconIndex, 1);
          return false; // remove bullet
        }
        return true;
      });
    });
  };

  // Show feedback for hits
  const showFeedback = (x, y, isCorrect, points, iconName) => {
    feedbacksRef.current.push({
      x, y, isCorrect, points, name: iconName, time: Date.now(),
    });
  };

  // --------------------------------------------------
  //                 MAIN GAME LOOP
  // --------------------------------------------------
  const gameLoop = () => {
    if (!gameStarted || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (gameStarted) {
      // 1) Draw rocket
      const { x, y, width, height } = gunRef.current;
      ctx.drawImage(rocketImage.current, x, y, width, height);

      // 2) Draw icons
      iconsRef.current.forEach((icon) => {
        if (!icon.hit) {
          ctx.save();
          const radius = 10;
          const [ix, iy] = [icon.x, icon.y];
          const [w, h] = [50, 50];

          ctx.beginPath();
          ctx.moveTo(ix + radius, iy);
          ctx.lineTo(ix + w - radius, iy);
          ctx.quadraticCurveTo(ix + w, iy, ix + w, iy + radius);
          ctx.lineTo(ix + w, iy + h - radius);
          ctx.quadraticCurveTo(ix + w, iy + h, ix + w - radius, iy + h);
          ctx.lineTo(ix + radius, iy + h);
          ctx.quadraticCurveTo(ix, iy + h, ix, iy + h - radius);
          ctx.lineTo(ix, iy + radius);
          ctx.quadraticCurveTo(ix, iy, ix + radius, iy);
          ctx.closePath();
          ctx.clip();

          ctx.drawImage(icon.image, ix, iy, w, h);
          ctx.restore();

          icon.y += 0.7; // slow fall
        }
      });

      // Filter off-screen
      iconsRef.current = iconsRef.current.filter(ic => ic.y < canvas.height);

      // If no icons remain and there's still time => new category
      if (iconsRef.current.length === 0 && timeLeft > 0) {
        playSound('levelup');
        NewCategoryMission();
      }

      // 3) Draw bullets
      bulletsRef.current.forEach(b => {
        ctx.drawImage(fireballImage, b.x, b.y, 20, 20);
        b.y -= 5;
      });
      bulletsRef.current = bulletsRef.current.filter(b => b.y > 0);

      // 4) Draw feedback
      const now = Date.now();
      feedbacksRef.current = feedbacksRef.current.filter(feedback => {
        const elapsed = now - feedback.time;
        if (elapsed < 3000) {
          ctx.shadowColor = 'rgba(0, 0, 0, 0.5)';
          ctx.shadowBlur = 4;
          ctx.fillStyle = feedback.isCorrect ? '#4CAF50' : '#F44336';
          ctx.font = 'bold 28px Arial';

          const pointsText = feedback.points > 0 ? `+${feedback.points}` : `${feedback.points}`;
          ctx.fillText(pointsText, feedback.x + 10, feedback.y - 20);

          ctx.font = '16px Arial';
          ctx.fillText(feedback.name, feedback.x + 60, feedback.y + 25);

          ctx.font = 'bold 55px Arial';
          ctx.fillText(feedback.isCorrect ? '✔' : '✘', feedback.x + 10, feedback.y + 30);

          ctx.shadowBlur = 0;
          return true;
        }
        return false;
      });

      // 5) Collisions
      checkCollisions();

      // 6) Particles
      particlesRef.current = particlesRef.current.filter(p => {
        if (p.lifetime > 0 && p.size > 0) {
          p.update();
          p.draw(ctx);
          return true;
        }
        return false;
      });
    }

    requestAnimationFrame(gameLoop);
  };

  // --------------------------------------------------
  //     PARTICLES (EXPLOSIONS)
  // --------------------------------------------------
  class Particle {
    constructor(x, y, color) {
      this.x = x;
      this.y = y;
      this.color = color;
      this.size = Math.random() * 3 + 2;
      this.speedX = Math.random() * 6 - 3;
      this.speedY = Math.random() * 6 - 3;
      this.lifetime = 1;
      this.initialSize = this.size;
    }
    update() {
      this.x += this.speedX;
      this.y += this.speedY;
      this.lifetime -= 0.02;
      this.size = Math.max(0, this.initialSize * this.lifetime);
    }
    draw(ctx) {
      if (this.size <= 0) return;
      ctx.fillStyle = this.color;
      ctx.globalAlpha = this.lifetime;
      ctx.beginPath();
      ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1;
    }
  }

  const createExplosion = (x, y, color) => {
    for (let i = 0; i < 20; i++) {
      particlesRef.current.push(new Particle(x, y, color));
    }
  };

  // --------------------------------------------------
  //                SOUNDS
  // --------------------------------------------------
  useEffect(() => {
    const soundFiles = {
      shoot:    `${S3_BUCKET_URL}/games/sounds/pistol_sound.mp3`,
      correct:  `${S3_BUCKET_URL}/games/sounds/correct_sound.mp3`,
      incorrect:`${S3_BUCKET_URL}/games/sounds/incorrect_sound.mp3`,
      levelup:  `${S3_BUCKET_URL}/games/sounds/levelup.mp3`
    };

    const createSafeAudio = (path) => {
      const audio = new Audio();
      return new Promise((resolve) => {
        audio.addEventListener('error', () => {
          console.warn(`Sound file not found: ${path}`);
          resolve(null);
        });
        audio.addEventListener('canplaythrough', () => {
          resolve(audio);
        });
        setTimeout(() => resolve(null), 2000);
        audio.src = path;
      });
    };

    const loadAllSounds = async () => {
      const loaded = {};
      for (const [key, path] of Object.entries(soundFiles)) {
        loaded[key] = await createSafeAudio(path);
      }
      sounds.current = loaded;
      setSoundsLoaded(true);
    };

    loadAllSounds();

    return () => {
      Object.values(sounds.current).forEach((sound) => {
        if (sound) {
          sound.pause();
          sound.src = '';
        }
      });
    };
  }, []);

  const toggleMute = () => {
    setIsMuted(!isMuted);
    Object.values(sounds.current).forEach(sound => {
      if (sound) sound.muted = !sound.muted;
    });
  };

  const playSound = (soundName) => {
    const sound = sounds.current[soundName];
    if (sound && !isMuted) {
      try {
        sound.currentTime = 0;
        sound.volume = 0.3;
        sound.play().catch((err) => {
          console.warn(`Error playing sound ${soundName}:`, err);
        });
      } catch (err) {
        console.warn(`Error with sound ${soundName}:`, err);
      }
    }
  };

  // --------------------------------------------------
  //               TIMER & GAME OVER
  // --------------------------------------------------
  useEffect(() => {
    if (gameStarted && !gameOver && timeLeft > 0) {
      const t = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
      return () => clearInterval(t);
    } else if (timeLeft === 0 && !gameOverHandled) {
      handleGameOver();
    }
  }, [timeLeft, gameOver, gameOverHandled, gameStarted]);

  const handleGameOver = () => {
    if (gameOverHandled) return;
    setGameOver(true);
    setGameOverHandled(true);

    const newScore = { name: playerName, score };
    const newList = [...highScores, newScore].sort((a, b) => b.score - a.score).slice(0, 5);
    setHighScores(newList);
    localStorage.setItem('highScores', JSON.stringify(newList));
  };

  // --------------------------------------------------
  //               CHEER MESSAGES
  // --------------------------------------------------
  const [cheerMessage, setCheerMessage] = useState('');
  const [showCheerMessage, setShowCheerMessage] = useState(false);

  const cheerleaderMessages = {
    goodShot: [
      "Great shot! You're an AWS Pro! 🌟",
      "Amazing cloud skills! Keep it up! 🎯",
      "You're on fire in the cloud! 🔥",
      "That's how AWS experts do it! 👏",
    ],
    combo: [
      "Cloud combo! 🎮",
      "You're scaling infinitely! ⚡",
      "What an AWS streak! 🌈",
    ],
    timeWarning: [
      "30 seconds left - you're highly available! ⏰",
      "Time for the final deployment! 💪",
      "Make every compute unit count! ⭐",
    ],
    encouragement: [
      "You've got this, cloud warrior! 🚀",
      "Keep going! You're AWS certified material! 🌟",
      "I believe in your cloud powers! 💫",
      "Show them your AWS expertise! 💪",
    ],
    highScore: [
      "New high score! You're going serverless! 🏆",
      "You're breaking cloud records! 🎖️",
      "Legendary AWS performance! 👑",
    ]
  };

  const showCheerleaderMessage = (category) => {
    const arr = cheerleaderMessages[category];
    if (!arr) return;
    const randMsg = arr[Math.floor(Math.random() * arr.length)];
    setCheerMessage(randMsg);
    setShowCheerMessage(true);

    setTimeout(() => {
      setShowCheerMessage(false);
    }, 3000);
  };

  // Encouragement every 10s
  useEffect(() => {
    const interval = setInterval(() => {
      if (timeLeft > 0 && Math.random() < 0.3) {
        showCheerleaderMessage('encouragement');
      }
    }, 10000);
    return () => clearInterval(interval);
  }, [timeLeft]);

  // 30s left => "timeWarning"
  useEffect(() => {
    if (timeLeft === 30) {
      showCheerleaderMessage('timeWarning');
    }
  }, [timeLeft]);

  // --------------------------------------------------
  //               MODALS & UI
  // --------------------------------------------------
  const [showRocketModal, setShowRocketModal] = useState(true);

  const rocketOptions = [
    { id: `${S3_ROCKET_PATH}/rocket1.png`, name: 'Modern Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket2.png`, name: 'Power Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket3.png`, name: 'Stealth Rocket' },
    { id: `${S3_ROCKET_PATH}/rocket4.png`, name: 'Classic Rocket' },
  ];

  const handleRocketSelect = (rocketId) => {
    setSelectedRocket(rocketId);
    localStorage.setItem('selectedRocket', rocketId);
    rocketImage.current.src = rocketId;
    setShowRocketModal(false);
    setGameStarted(true);
  };

  // Name submission
  const handleNameSubmit = (e) => {
    e.preventDefault();
    if (tempPlayerName.trim().length < 2) {
      setNameError('Name must be at least 2 characters long');
      return;
    }
    if (tempPlayerName.trim().length > 15) {
      setNameError('Name must be less than 15 characters');
      return;
    }
    setPlayerName(tempPlayerName.trim());
    localStorage.setItem('playerName', tempPlayerName.trim());
    setShowNameModal(false);
  };

  // --------------------------------------------------
  //                    RENDER
  // --------------------------------------------------
  return (
    <div className="gameCanvas-container">
      <h1 className="gameCanvas-game-title">AWS Cloud Shooter</h1>
      <div className="gameCanvas-game-content">
        <div className="gameCanvas-canvas-wrapper">
          <canvas ref={canvasRef} className="gameCanvas-game-canvas" />
        </div>

        <div className="gameCanvas-instruction-panel">
          {/* Player / Score */}
          <div className="gameCanvas-player-info">
            <div className="gameCanvas-player-name">
              Player: {playerName}
            </div>
            <div className="gameCanvas-score-display">
              <span role="img" aria-label="alien">👾</span>
              {' '}Score: {score}{' '}
              <span role="img" aria-label="joystick">🕹️</span>
              {soundsLoaded && Object.values(sounds.current).some(s => s) && (
                <button
                  className="gameCanvas-sound-toggle"
                  onClick={toggleMute}
                  aria-label="Toggle sound"
                >
                  {isMuted ? '🔇' : '🔊'}
                </button>
              )}
            </div>
          </div>

          {/* Timer */}
          <div className="gameCanvas-timer-display">
            Time: {timeLeft}s
          </div>

          {/* Score Explanation */}
          <div className="gameCanvas-score-explanation">
            <h4>How to Score:</h4>
            <ul>
              <li>• Hit correct icon: +5 points</li>
              <li>• Height bonus: up to +20</li>
              <li>• Wrong hit: -5 points</li>
              <li>• Tip: Shoot icons as high as possible!</li>
            </ul>
          </div>

          {/* High Scores */}
          <div className="gameCanvas-high-scores">
            <h4>High Scores</h4>
            <ul>
              {highScores.map((entry, i) => (
                <li key={i}>
                  <span className="gameCanvas-high-score-name">{entry.name}:</span> {entry.score}
                </li>
              ))}
            </ul>
          </div>

          {/* Current Mission */}
          <div className="gameCanvas-mission-container">
            <h3 className="gameCanvas-mission-title">Current Mission</h3>
            <div className="gameCanvas-mission-text">
              {missionText}
            </div>
          </div>
        </div>
      </div>

      {/* Rocket Modal */}
      {showRocketModal && (
        <div className="gameCanvas-modal-overlay">
          <div className="gameCanvas-rocket-selection-modal">
            <h2>Choose Your Rocket</h2>
            <div className="gameCanvas-rocket-grid">
              {rocketOptions.map((r) => (
                <div
                  key={r.id}
                  className={`gameCanvas-rocket-option ${selectedRocket === r.id ? 'selected' : ''}`}
                  onClick={() => handleRocketSelect(r.id)}
                >
                  <img src={r.id} alt={r.name} />
                  <p>{r.name}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Game Over */}
      {gameOver && (
        <div className="gameCanvas-game-over">
          <h3>Game Over!</h3>
          <button onClick={() => window.location.reload()}>
            Play Again
          </button>
        </div>
      )}

      {/* Cheerleader Messages */}
      {showCheerMessage && (
        <div className="gameCanvas-cheerleader-container">
          <div className="gameCanvas-cheerleader-character">
            {/* Update path if you store the cheerleader somewhere else */}
            <img
              src={`${S3_BUCKET_URL}/games/utilities/cheerleader.png`}
              alt="Cheerleader"
            />
          </div>
          <div className="gameCanvas-cheer-message">
            {cheerMessage}
          </div>
        </div>
      )}

      {/* Name Modal */}
      {showNameModal && (
        <div className="gameCanvas-modal-overlay">
          <div className="gameCanvas-modal">
            <h2>Welcome to AWS Cloud Shooter!</h2>
            <p>Enter your name to start the game:</p>
            <form onSubmit={handleNameSubmit}>
              <input
                type="text"
                value={tempPlayerName}
                onChange={(e) => {
                  setTempPlayerName(e.target.value);
                  setNameError('');
                }}
                placeholder="Your name"
                className="gameCanvas-name-input"
                autoFocus
              />
              {nameError && <div className="gameCanvas-name-error">{nameError}</div>}
              <button type="submit" className="gameCanvas-start-button">
                Start Game
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default GameCanvas;
